// ---- home ------------------------------------------------------------------

function render(): void {
  const app = document.getElementById("app")!;
  clear(app);
  app.appendChild(header());

  const v = state.view;
  if (v.kind === "restaurant") {
    app.appendChild(restaurantView(v.id));
    app.appendChild(footer());
    return;
  }
  if (v.kind === "catalogue") {
    app.appendChild(el("div", { class: "page" },
      el("button", { class: "detail-back", text: "‹ 返主頁", onclick: goHome }),
      catalogueSection()
    ));
    app.appendChild(footer());
    return;
  }
  if (v.kind === "memories") {
    app.appendChild(el("div", { class: "page" },
      el("button", { class: "detail-back", text: "‹ 返主頁", onclick: goHome }),
      memoryTimeline(allMemories())
    ));
    app.appendChild(footer());
    return;
  }

  // ---- home hub: recall is the hero; catalogue is just a window ----
  const mems = allMemories();
  app.appendChild(askSection()); // 主角 = recall
  if (state.thinking) app.appendChild(thinkingCard());
  else if (state.answer) app.appendChild(answerCard(state.answer));
  app.appendChild(logSection()); // 記低今餐
  if (mems.length === 0) app.appendChild(onboardCard());
  else app.appendChild(memoryHubSection(mems)); // 你嘅飲食記憶（最近幾段）
  app.appendChild(catalogueWindow()); // 餐廳目錄 window
  app.appendChild(footer());
}

