function answerCard(a: RecallResult): HTMLElement {
  const bubble = el("div", { class: "answer-bubble" },
    el("p", { class: "answer-text" },
      ...a.text.split("\n").flatMap((line, i) => (i ? [el("br"), line] : [line]))
    )
  );
  if (a.cited.length) {
    bubble.appendChild(el("p", { class: "cite-label", text: `我睇返 ${a.cited.length} 段相關記憶：` }));
    bubble.appendChild(citedList(a.cited));
  }
  // Clickable suggestion cards for un-visited picks (+ feedback + expandable reason).
  if (a.suggestions?.length) {
    bubble.appendChild(suggestionCards(a.suggestions, a.detail));
  } else if (!a.cited.length) {
    bubble.appendChild(el("p", { class: "cite-label muted", text: "（唔會老作 — 冇相關記憶就照直講）" }));
  }
  return el("section", { class: "answer-card kind-" + a.kind },
    el("div", { class: "answer-avatar", text: "🍜" }),
    bubble
  );
}

function suggestionCards(items: SuggestionItem[], detail?: string): HTMLElement {
  const wrap = el("div", { class: "sugg-list" });
  for (const s of items) wrap.appendChild(suggestionCard(s));
  wrap.appendChild(el("p", { class: "sugg-src", text: "基於 Google 評價 + 你口味，唔係你自己試過。" }));
  if (detail) {
    wrap.appendChild(
      el("details", { class: "sugg-detail" },
        el("summary", { text: "睇詳細理由" }),
        el("p", { class: "sugg-detail-text" }, ...detail.split("\n").flatMap((line, i) => (i ? [el("br"), line] : [line])))
      )
    );
  }
  return wrap;
}

function dismissSuggestion(s: SuggestionItem, kind: "dismissed" | "visited", msg: string): void {
  addSuggestFeedback(kind, s.restaurantId);
  if (state.answer?.suggestions) {
    state.answer.suggestions = state.answer.suggestions.filter((x) => x.restaurantId !== s.restaurantId);
  }
  toast(msg);
  render();
}

