// ---- collection: user self-input (ZERO AI vision) --------------------------

// Distinct past dish names — for autocomplete (own history ranks first).
function pastDishNames(restaurantId?: string): { atRestaurant: string[]; anywhere: string[] } {
  const anywhere: string[] = [];
  const atRestaurant: string[] = [];
  const seenA = new Set<string>();
  const seenR = new Set<string>();
  for (const m of allMemories())
    for (const d of m.dishes) {
      if (!seenA.has(d.name)) { seenA.add(d.name); anywhere.push(d.name); }
      if (restaurantId && m.restaurantId === restaurantId && !seenR.has(d.name)) {
        seenR.add(d.name); atRestaurant.push(d.name);
      }
    }
  return { atRestaurant, anywhere };
}

