interface MealUnit {
  files: File[]; // photos for this meal (album groups can hold several)
  meta: PhotoMeta; // representative GPS + time
  area: string | null; // nearest FEHD district (from GPS), if any
}

// Read GPS+time, group album photos into meals, then log each meal in turn.
async function runPhotoQueue(files: FileList, source: Memory["source"]): Promise<void> {
  const arr = Array.from(files);
  const metas = await Promise.all(arr.map(readPhotoMeta));
  const units: MealUnit[] =
    source === "album"
      ? groupPhotos(metas).map((g) => ({
          files: g.indices.map((i) => arr[i]),
          meta: { lat: g.lat, lng: g.lng, time: g.time || undefined },
          area: g.lat != null ? nearestArea(g.lat, g.lng!) : null,
        }))
      : arr.map((f, i) => ({
          files: [f],
          meta: metas[i],
          area: metas[i].lat != null ? nearestArea(metas[i].lat!, metas[i].lng!) : null,
        }));

  let gi = 0;
  let saved = 0;
  const next = () => {
    if (gi >= units.length) {
      if (saved) toast(`加咗 ${saved} 餐入記憶 🎉`);
      render();
      return;
    }
    openLog(source, units[gi], gi, units.length, {
      onSaved: () => { saved++; gi++; next(); },
      onSkip: () => { gi++; next(); },
    });
  };
  next();
}

// User self-input (ZERO AI): GPS auto-narrows the restaurant to its district for
// a one-tap pick; dish typed with autocomplete. The photo is encrypted on-device.
function openLog(
  source: Memory["source"],
  unit: MealUnit,
  index: number,
  total: number,
  cb: { onSaved: () => void; onSkip: () => void },
  prefill?: Restaurant // pre-picked restaurant (from a detail page "再記一餐")
): void {
  let closed = false;
  const overlay = el("div", { class: "modal-overlay" });
  const close = (skip: boolean) => {
    if (closed) return;
    closed = true;
    overlay.remove();
    if (skip) cb.onSkip();
  };
  overlay.addEventListener("click", (e) => { if (e.target === overlay) close(true); });

  let picked: Restaurant | null = null;
  let chosenTags: string[] = [];
  const pickedLabel = el("p", { class: "log-picked", text: "" });
  const results = el("div", { class: "log-results" });

  // Dish autocomplete.
  const dishInput = el("input", { class: "log-dish", type: "text", placeholder: "食咗咩？（打頭幾個字揀）", autocomplete: "off" }) as HTMLInputElement;
  const dishSug = el("div", { class: "log-sug" });
  const refreshSug = () => {
    clear(dishSug);
    const { atRestaurant, anywhere } = pastDishNames(picked?.id);
    const cuisine = picked ? restaurantCuisines(picked) : [];
    const sugs = suggestDishes(dishInput.value, atRestaurant, anywhere, 8, cuisine);
    if (!dishInput.value.trim() && !sugs.length) return;
    for (const d of sugs)
      dishSug.appendChild(el("button", { class: "sug-chip", text: d.name, onclick: () => {
        dishInput.value = d.name; chosenTags = d.tasteTags; clear(dishSug);
      } }));
  };
  dishInput.addEventListener("input", () => { chosenTags = []; refreshSug(); });
  dishInput.addEventListener("focus", refreshSug);

  // Per-dish rating + reason chips + optional note. Committed dishes accumulate,
  // so one meal can carry several dishes, each with its own 👍/😐/👎.
  const dishes: Dish[] = [];
  let curRating: Rating | null = null;
  let curReasons: string[] = [];
  const ratingHint = el("p", { class: "log-hint" });
  const ratingRow = el("div", { class: "rate-row" });
  const reasonWrap = el("div", { class: "reason-wrap" });
  const noteInput = el("input", { class: "log-note", type: "text", placeholder: "其他…（可選，唔強制）", autocomplete: "off" }) as HTMLInputElement;
  const dishList = el("div", { class: "dish-list" });

  const renderReasons = () => {
    clear(reasonWrap);
    for (const r of reasonsFor(curRating)) {
      const on = curReasons.includes(r);
      reasonWrap.appendChild(el("button", { class: "reason-chip" + (on ? " on" : ""), text: r, onclick: () => {
        curReasons = curReasons.includes(r) ? curReasons.filter((x) => x !== r) : [...curReasons, r];
        renderReasons();
      } }));
    }
  };
  const renderRating = () => {
    clear(ratingRow);
    for (const [val, label] of RATING_BTNS) {
      ratingRow.appendChild(el("button", { class: "rate-btn " + val + (curRating === val ? " on" : ""), text: label, onclick: () => {
        curRating = curRating === val ? null : val;
        curReasons = []; // reasons are rating-specific
        ratingHint.textContent = "";
        renderRating(); renderReasons();
      } }));
    }
  };

  // A dish needs a NAME to be committed; the rating is optional (can be added
  // later via ＋評價). This keeps「加多一道菜」from ever blocking / leaving stale text.
  const currentDish = (): Dish | null => {
    const name = dishInput.value.trim();
    if (!name) return null;
    const tags = chosenTags.length ? chosenTags : tagsFor(name);
    return { name, tasteTags: tags, rating: curRating ?? undefined, reasons: curReasons.slice(), note: noteInput.value.trim() || undefined };
  };
  const resetSub = () => {
    dishInput.value = ""; chosenTags = []; curRating = null; curReasons = []; noteInput.value = "";
    clear(dishSug); renderRating(); renderReasons();
  };
  const renderDishList = () => {
    clear(dishList);
    dishes.forEach((d, i) => {
      dishList.appendChild(el("div", { class: "dish-row" },
        el("span", { class: "dish-rate", text: d.rating ? RATING_EMOJI[d.rating] : "" }),
        el("span", { class: "dish-name", text: d.name }),
        ...(d.reasons ?? []).map((r) => el("span", { class: "dish-reason", text: r })),
        el("button", { class: "dish-del", text: "✕", "aria-label": "移除", onclick: () => { dishes.splice(i, 1); renderDishList(); } })
      ));
    });
  };

  const addBtn = el("button", { class: "log-add", text: "＋ 加多一道菜", onclick: () => {
    const d = currentDish();
    if (!d) { ratingHint.textContent = "打返食咗咩"; return; }
    dishes.push(d); resetSub(); renderDishList(); dishInput.focus();
  } });

  renderRating();

  const pick = (r: Restaurant) => {
    picked = r;
    pickedLabel.textContent = `✓ ${r.name.tc}（${r.area}）`;
    clear(results);
    refreshSug();
  };
  if (prefill) pick(prefill); // detail-page "再記一餐" → restaurant already known

  // GPS → district → one-tap candidates (own past visits in that district first).
  let gpsBanner: HTMLElement | null = null;
  if (!prefill && unit.area) {
    const visitedIds = new Set(allMemories().map((m) => m.restaurantId));
    const nearby = state.cat!.restaurants
      .filter((r) => r.area === unit.area)
      .sort((a, b) => Number(visitedIds.has(b.id)) - Number(visitedIds.has(a.id)))
      .slice(0, 6);
    const chips = el("div", { class: "gps-chips" },
      ...nearby.map((r) =>
        el("button", { class: "gps-chip", text: r.name.tc, onclick: () => pick(r) })
      )
    );
    gpsBanner = el("div", { class: "gps-banner" },
      el("p", { class: "gps-lead", text: `📍 相顯示喺「${unit.area}」附近 — 係咪呢間？` }),
      chips
    );
  }

  // Restaurant search fallback.
  const searchInput = el("input", { class: "log-search", type: "text", placeholder: unit.area ? "唔啱？搜尋其他餐廳…" : "喺邊間食？搜尋餐廳…", autocomplete: "off" }) as HTMLInputElement;
  searchInput.addEventListener("input", () => {
    clear(results);
    for (const r of searchRestaurants(state.cat!, searchInput.value, 6))
      results.appendChild(el("button", { class: "log-result", text: `${r.name.tc}　·　${r.area}`, onclick: () => {
        pick(r); searchInput.value = r.name.tc;
      } }));
  });

  const save = el("button", { class: "log-save", text: "儲入記憶", onclick: async () => {
    const pending = currentDish();
    const all = pending ? [...dishes, pending] : dishes.slice();
    if (all.length === 0) {
      ratingHint.textContent = "打返食咗咩";
      dishInput.focus();
      return;
    }
    if (!picked) { pickedLabel.textContent = "請先揀返間餐廳。"; return; }
    save.disabled = true;
    const photoId = unit.files[0] ? ((await putPhoto(unit.files[0])) ?? undefined) : undefined;
    const aggTags = [...new Set(all.flatMap((d) => d.tasteTags))];
    addMemory({
      ts: unit.meta.time || Date.now(),
      restaurantId: picked.id,
      restaurantName: picked.name.tc || picked.name.en,
      area: picked.area,
      dishes: all,
      tasteTags: aggTags,
      source,
      confidence: 1,
      photoId,
    });
    closed = true;
    overlay.remove();
    cb.onSaved();
  } });

  const firstFile = unit.files[0];
  const preview = firstFile
    ? (el("img", { class: "log-preview", src: URL.createObjectURL(firstFile), alt: "" }) as HTMLImageElement)
    : null;
  if (preview) preview.addEventListener("load", () => URL.revokeObjectURL(preview.src));

  const many = unit.files.length > 1;
  const title =
    source === "manual"
      ? `再記一餐${prefill ? "：" + prefill.name.tc : ""}`
      : total > 1
        ? `第 ${index + 1}/${total} 餐`
        : source === "receipt"
          ? "記低張單"
          : "記低呢餐";

  overlay.appendChild(
    el("div", { class: "modal-card" },
      el("button", { class: "modal-close", text: "✕", onclick: () => close(true) }),
      el("h2", { class: "log-title", text: title }),
      preview,
      many ? el("p", { class: "log-count", text: `📸 呢餐 ${unit.files.length} 張相` }) : null,
      el("label", { class: "log-lbl", text: "食咗咩" }),
      dishInput,
      dishSug,
      el("label", { class: "log-lbl", text: "好唔好食？（可選，一 tap）" }),
      ratingRow,
      reasonWrap,
      noteInput,
      ratingHint,
      addBtn,
      dishList,
      el("label", { class: "log-lbl", text: "邊間餐廳" }),
      gpsBanner,
      searchInput,
      results,
      pickedLabel,
      save,
      total > 1 ? el("button", { class: "log-skip", text: "跳過呢餐", onclick: () => close(true) }) : null
    )
  );
  document.body.appendChild(overlay);
  dishInput.focus();
}

// ---- memory timeline -------------------------------------------------------

function memoryTimeline(mems: Memory[]): HTMLElement {
  const section = el("section", { class: "timeline" },
    el("h3", { class: "sec-title" }, el("span", { text: `我嘅飲食記憶（${mems.length}）` }), privTone())
  );
  if (mems.length === 0) {
    section.appendChild(el("p", { class: "empty", text: "未有記憶。掃相簿或者影一餐，就開始生長。" }));
    return section;
  }
  section.appendChild(unlockBar());
  for (const g of groupByRestaurant(mems)) section.appendChild(restaurantGroupCard(g));
  return section;
}

// "再記 N 間就更準" unlock progress — encourages logging (Beli-style).
const UNLOCK_MILESTONES = [3, 5, 10, 20];
function unlockBar(): HTMLElement {
  const n = groupByRestaurant(allMemories()).length;
  const next = UNLOCK_MILESTONES.find((m) => m > n);
  if (!next) return el("div", { class: "unlock done", text: "🎯 你嘅推薦已經好個人化 — keep 住記，越記越準。" });
  const pct = Math.min(100, Math.round((n / next) * 100));
  return el("div", { class: "unlock" },
    el("p", { class: "unlock-text", text: `再記 ${next - n} 間，個人化推薦會更準 🎯` }),
    el("div", { class: "unlock-bar" }, el("div", { class: "unlock-fill", style: `width:${pct}%` })),
    el("p", { class: "unlock-sub", text: `${n} / ${next} 間` })
  );
}

const privTone = () => el("span", { class: "priv-tone", text: "🔒 只你自己睇" });

// Group memories by restaurant (newest visit first) so one restaurant = one card.
function groupByRestaurant(mems: Memory[]): Memory[][] {
  const map = new Map<string, Memory[]>();
  for (const m of mems) {
    const g = map.get(m.restaurantId);
    if (g) g.push(m);
    else map.set(m.restaurantId, [m]);
  }
  return [...map.values()].sort((a, b) => Math.max(...b.map((m) => m.ts)) - Math.max(...a.map((m) => m.ts)));
}

// One card per restaurant: dishes across all visits (deduped by name, each still
// tappable to edit its rating). Name links to the detail page; ✕ clears the whole
// restaurant's records (confirm). Presentation only — same store/edit/delete fns.
function restaurantGroupCard(mems: Memory[]): HTMLElement {
  const visits = [...mems].sort((a, b) => b.ts - a.ts);
  const rep = visits[0];
  const photoId = visits.find((v) => v.photoId)?.photoId;
  const avatar = memAvatar(typeIconForId(rep.restaurantId), photoId);

  const seen = new Set<string>();
  const refs: { mem: Memory; idx: number; dish: Dish }[] = [];
  for (const v of visits) v.dishes.forEach((d, i) => { if (!seen.has(d.name)) { seen.add(d.name); refs.push({ mem: v, idx: i, dish: d }); } });

  const dishBox = el("div", { class: "mem-dishes" });
  if (refs.length) {
    for (const { mem, idx, dish } of refs) {
      dishBox.appendChild(
        el("button", { class: "mem-dish editable", "aria-label": "改評價", onclick: () => openDishEditor(mem, idx) },
          dish.rating
            ? el("span", { class: "mem-rate " + dish.rating, text: RATING_EMOJI[dish.rating] })
            : el("span", { class: "mem-rate-add", text: "＋評價" }),
          el("span", { class: "mem-dish-name", text: dish.name }),
          ...(dish.reasons ?? []).map((r) => el("span", { class: "mem-reason", text: r }))
        )
      );
    }
  } else {
    dishBox.appendChild(el("span", { class: "mem-dish-empty", text: rep.source === "onboarding" ? "你話你常去 — 影低食咗乜就記得返" : "—" }));
  }

  const tags = [...new Set(visits.flatMap((v) => v.tasteTags))].slice(0, 5);

  return el("div", { class: "mem" },
    avatar,
    el("div", { class: "mem-main" },
      el("div", { class: "mem-top" },
        el("button", { class: "mem-name mem-name-link", text: rep.restaurantName, onclick: () => openRestaurant(rep.restaurantId) }),
        el("span", { class: "mem-ago", text: ago(rep.ts) })
      ),
      el("div", { class: "mem-metaline" },
        rep.area ? el("span", { class: "mem-area", text: "📍 " + districtZh(rep.area) }) : null,
        visits.length > 1 ? el("span", { class: "mem-visits", text: `· 去過 ${visits.length} 次` }) : null
      ),
      dishBox,
      tags.length ? el("div", { class: "mem-tags" }, ...tags.map((t) => el("span", { class: "mem-tag", text: t }))) : null
    ),
    el("button", {
      class: "mem-del",
      text: "✕",
      "aria-label": "刪除",
      onclick: () => {
        if (!confirm(`刪除你喺「${rep.restaurantName}」嘅所有記錄（${visits.length} 次）？`)) return;
        for (const v of visits) { if (v.photoId) void delPhoto(v.photoId); deleteMemory(v.id); }
        render();
      },
    })
  );
}

// One memory row, reused by the timeline and the restaurant detail page.
// Dishes are tappable to add/edit a rating post-hoc; the name links to the
// restaurant detail page unless we're already on it.
function memoryRow(m: Memory, opts: { linkName: boolean }): HTMLElement {
  const avatar = memAvatar(typeIconForId(m.restaurantId), m.photoId);

  const nameEl = opts.linkName
    ? el("button", { class: "mem-name mem-name-link", text: m.restaurantName, onclick: () => openRestaurant(m.restaurantId) })
    : el("span", { class: "mem-name", text: m.restaurantName });

  const dishBox = el("div", { class: "mem-dishes" });
  if (m.dishes.length) {
    m.dishes.forEach((d, i) => {
      dishBox.appendChild(
        el("button", { class: "mem-dish editable", "aria-label": "改評價", onclick: () => openDishEditor(m, i) },
          d.rating
            ? el("span", { class: "mem-rate " + d.rating, text: RATING_EMOJI[d.rating] })
            : el("span", { class: "mem-rate-add", text: "＋評價" }),
          el("span", { class: "mem-dish-name", text: d.name }),
          ...(d.reasons ?? []).map((r) => el("span", { class: "mem-reason", text: r }))
        )
      );
    });
  } else {
    dishBox.appendChild(el("span", { class: "mem-dish-name", text: "—" }));
  }

  return el("div", { class: "mem" },
    avatar,
    el("div", { class: "mem-main" },
      el("div", { class: "mem-top" }, nameEl, el("span", { class: "mem-ago", text: ago(m.ts) })),
      m.area ? el("div", { class: "mem-area", text: "📍 " + m.area }) : null,
      dishBox,
      el("div", { class: "mem-tags" },
        ...m.tasteTags.slice(0, 5).map((t) => el("span", { class: "mem-tag", text: t })),
        el("span", { class: "mem-src", text: srcLabel(m.source) })
      )
    ),
    el("button", {
      class: "mem-del",
      text: "✕",
      "aria-label": "刪除",
      onclick: () => {
        if (m.photoId) void delPhoto(m.photoId); // delete the encrypted photo too
        deleteMemory(m.id);
        render();
      },
    })
  );
}

// Post-hoc rating editor for one dish inside an existing memory.
function openDishEditor(mem: Memory, idx: number): void {
  const dish = mem.dishes[idx];
  let curRating: Rating | null = dish.rating ?? null;
  let curReasons: string[] = dish.reasons ? [...dish.reasons] : [];

  const overlay = el("div", { class: "modal-overlay" });
  const close = () => overlay.remove();
  overlay.addEventListener("click", (e) => { if (e.target === overlay) close(); });

  const ratingRow = el("div", { class: "rate-row" });
  const reasonWrap = el("div", { class: "reason-wrap" });
  const noteInput = el("input", { class: "log-note", type: "text", placeholder: "其他…（可選）", value: dish.note ?? "", autocomplete: "off" }) as HTMLInputElement;

  const renderReasons = () => {
    clear(reasonWrap);
    for (const r of reasonsFor(curRating)) {
      const on = curReasons.includes(r);
      reasonWrap.appendChild(el("button", { class: "reason-chip" + (on ? " on" : ""), text: r, onclick: () => {
        curReasons = on ? curReasons.filter((x) => x !== r) : [...curReasons, r];
        renderReasons();
      } }));
    }
  };
  const renderRating = () => {
    clear(ratingRow);
    for (const [val, label] of RATING_BTNS) {
      ratingRow.appendChild(el("button", { class: "rate-btn " + val + (curRating === val ? " on" : ""), text: label, onclick: () => {
        curRating = curRating === val ? null : val;
        curReasons = [];
        renderRating(); renderReasons();
      } }));
    }
  };
  renderRating(); renderReasons();

  const saveBtn = el("button", { class: "log-save", text: "存返評價", onclick: () => {
    const updated: Memory = {
      ...mem,
      dishes: mem.dishes.map((d, i) =>
        i === idx
          ? { ...d, rating: curRating ?? undefined, reasons: curReasons.slice(), note: noteInput.value.trim() || undefined }
          : d
      ),
    };
    updateMemory(updated);
    close();
    render();
  } });

  overlay.appendChild(
    el("div", { class: "modal-card" },
      el("button", { class: "modal-close", text: "✕", onclick: close }),
      el("h2", { class: "log-title", text: dish.name }),
      el("label", { class: "log-lbl", text: "好唔好食？（一 tap）" }),
      ratingRow,
      reasonWrap,
      noteInput,
      saveBtn
    )
  );
  document.body.appendChild(overlay);
}

// ---- restaurant detail page ------------------------------------------------

// Merged taste tags (onboarding seed + memory-derived) for personalisation.
function userLikedTags(): string[] {
  return [...new Set([...getTasteSeed(), ...deriveTasteProfile(allMemories()).liked])];
}

// Banner: a real user photo if we have one, else a map-style placeholder built
// from the district/address (no map API — zero cost, private, honest).
function detailBanner(r: Restaurant | null, name: string, photoId?: string): HTMLElement {
  if (photoId) {
    const banner = el("div", { class: "detail-banner" });
    const img = el("img", { class: "db-photo", alt: name }) as HTMLImageElement;
    getPhotoUrl(photoId).then((url) => {
      if (url) { img.src = url; img.addEventListener("load", () => URL.revokeObjectURL(url), { once: true }); }
    });
    banner.appendChild(img);
    return banner;
  }
  return el("div", { class: "detail-banner map" },
    el("div", { class: "db-grid" }),
    el("div", { class: "db-pin", text: "📍" }),
    el("div", { class: "db-place" },
      el("div", { class: "db-area", text: r ? districtZh(r.area) : "" }),
      r?.addr ? el("div", { class: "db-addr", text: r.addr }) : null
    )
  );
}

// Directions (a Google Maps search link — no API, no cost) + Call (fetches the
// phone live from Google on demand; never stored, per ToS).
function detailActions(r: Restaurant, name: string): HTMLElement {
  const q = encodeURIComponent(`${r.name.tc || name} ${r.addr || districtZh(r.area)}`);
  const directions = el("a", { class: "act-btn", href: `https://www.google.com/maps/search/?api=1&query=${q}`, target: "_blank", rel: "noopener" }, "🧭 路線");
  let phone: string | null = null;
  const call = el("button", { class: "act-btn" }, "📞 打電話") as HTMLButtonElement;
  call.onclick = async () => {
    if (phone) { location.href = `tel:${phone}`; return; }
    if (!placesEnabled()) { toast("電話要接 Google 先攞到"); return; }
    call.disabled = true; call.textContent = "查緊 Google…";
    const res = await fetchPlaces(r.name.tc || name, r.addr);
    call.disabled = false; call.textContent = "📞 打電話";
    if (res?.ok && res.matched && res.display?.phone) { phone = res.display.phone; location.href = `tel:${phone}`; }
    else toast("Google 攞唔到呢間電話");
  };
  return el("div", { class: "detail-actions" }, call, directions);
}

function restaurantView(id: string): HTMLElement {
  const r = byId(state.cat!, id);
  const visits = allMemories().filter((m) => m.restaurantId === id); // newest first
  const name = r?.name.tc || visits[0]?.restaurantName || "餐廳";

  const section = el("section", { class: "detail" },
    el("button", { class: "detail-back", text: "‹ 返去", onclick: goHome })
  );

  // Banner: a user photo if any visit has one, else a map-style banner (address/區).
  const photoId = visits.find((v) => v.photoId)?.photoId;
  section.appendChild(detailBanner(r, name, photoId));

  // Title + one-line tags (type · occasion · price? · cuisine?) + personalisation.
  const liked = userLikedTags();
  const match = r ? tasteMatch(r, liked) : null;
  const cachedPrice = r ? getPlaceFacts(r.id)?.priceLevel : null;
  const tagRow = el("div", { class: "detail-tags" });
  if (r) {
    tagRow.appendChild(el("span", { class: "dtag dtag-type", text: typeLabel(r.type) }));
    for (const o of occasionTags(r)) tagRow.appendChild(el("span", { class: "dtag", text: o }));
    if (cachedPrice && PRICE_ZH[cachedPrice]) tagRow.appendChild(el("span", { class: "dtag", text: "💵 " + PRICE_ZH[cachedPrice] }));
  }
  section.appendChild(el("h2", { class: "detail-name", text: name }));
  if (r) section.appendChild(el("p", { class: "detail-sub", text: `${districtZh(r.area)} · ${regionName(r.region)}` }));
  if (r) section.appendChild(tagRow);
  if (match) {
    section.appendChild(
      el("div", { class: "rec-badge " + match.level },
        el("span", { class: "rb-emoji", text: match.level === "high" ? "🎯" : "👍" }),
        el("span", {}, match.level === "high" ? "好啱你口味" : "幾啱你口味", el("span", { class: "rb-why", text: `（你鍾意${match.cuisines.join("、")}）` }))
      )
    );
  }

  // Action buttons: Directions (always, a maps link) + Call (fetches Google phone).
  if (r) section.appendChild(detailActions(r, name));

  // FEHD basics — intro, address, licence expiry, and licence-covered categories
  // shown NEUTRALLY (permission, not actual supply).
  if (r) {
    const facs = facilitiesOf(r);
    const exp = expiryLabel(r);
    section.appendChild(
      el("div", { class: "detail-fehd" },
        el("p", { class: "df-intro", text: introLine(r) }),
        r.addr ? el("div", { class: "df-addr", text: "📍 " + r.addr }) : null,
        facs.length
          ? el("div", { class: "df-lic" },
              el("span", { class: "df-lic-label", text: "🪪 牌照涵蓋（准許出售 · 未必實際有）：" }),
              ...facs.map((f) => el("span", { class: "fac-tag", text: `${f.icon} ${f.tag}` })))
          : null,
        exp ? el("div", { class: "df-exp", text: "牌照有效至 " + (r.exp ?? "") }) : null,
        el("p", { class: "df-src", text: "資料來源：食環署持牌食肆 open data" })
      )
    );
  } else {
    section.appendChild(el("p", { class: "df-addr", text: "（呢間唔喺 FEHD 目錄，只有你自己嘅記錄）" }));
  }

  // Layer ④ — Google, as a subtle secondary block (only when it can help + user taps).
  if (r && placesEnabled()) {
    section.appendChild(
      el("div", { class: "detail-google" },
        el("p", { class: "dg-label", text: "更多餐廳資料（Google）" }),
        googleBlock(r)
      )
    );
  }

  // The main event: your own records at this place.
  section.appendChild(
    el("h3", { class: "sec-title" },
      el("span", { text: `你喺呢間嘅記錄（${visits.length}）` }),
      el("span", { class: "priv-tone", text: "🔒 只你自己睇" })
    )
  );
  section.appendChild(
    el("button", { class: "detail-relog", text: "＋ 喺呢間再記一餐", onclick: () => {
      const rest: Restaurant =
        r ?? { id, name: { tc: name, en: name }, area: visits[0]?.area ?? "", region: "", type: "" };
      openLog("manual", { files: [], meta: {} as PhotoMeta, area: null }, 0, 1,
        { onSaved: () => render(), onSkip: () => {} }, rest);
    } })
  );
  if (visits.length) {
    for (const m of visits) section.appendChild(memoryRow(m, { linkName: false }));
  } else {
    section.appendChild(
      el("div", { class: "rec-empty" },
        el("div", { class: "rec-empty-icon", text: "🍽️" }),
        el("p", { class: "rec-empty-lead", text: "你未記錄過呢間。" }),
        el("p", { class: "rec-empty-sub", text: "撳「再記一餐」記低食過乜、好唔好食 — 下次就幫到你揀。" })
      )
    );
  }
  return section;
}

const PRICE_ZH: Record<string, string> = {
  PRICE_LEVEL_FREE: "免費",
  PRICE_LEVEL_INEXPENSIVE: "$",
  PRICE_LEVEL_MODERATE: "$$",
  PRICE_LEVEL_EXPENSIVE: "$$$",
  PRICE_LEVEL_VERY_EXPENSIVE: "$$$$",
};

// Google fallback: a tap fetches phone / hours / price / reviewSummary LIVE (never
// stored), shown with Google attribution. Only derived facts are persisted.
function googleBlock(r: Restaurant): HTMLElement {
  const wrap = el("div", { class: "gplace" });
  const known = getPlaceFacts(r.id);
  const hint = known
    ? "（Google 有" +
      [known.hasPhone && "電話", known.hasHours && "營業時間", known.priceLevel && "價位", known.hasSummary && "評論摘要"]
        .filter(Boolean)
        .join("、") +
      "）"
    : "電話・營業時間・價位・評論摘要";
  const btn = el("button", { class: "gplace-btn", text: `🔎 查 Google 補充　${hint}` }) as HTMLButtonElement;
  const out = el("div", { class: "gplace-out" });

  btn.onclick = async () => {
    btn.disabled = true;
    btn.textContent = "查緊 Google…";
    const res = await fetchPlaces(r.name.tc || r.name.en, r.addr);
    btn.disabled = false;
    clear(out);
    if (!res || res.ok === false) {
      const reason = res?.reason;
      out.appendChild(
        el("p", { class: "gplace-note", text:
          reason === "daily-cap" ? "今日 Google 查詢已到上限，睇返上面 FEHD 資料先。"
          : reason === "disabled" ? "Google 補充暫時未開。"
          : "Google 暫時攞唔到資料。" })
      );
      btn.textContent = "🔎 再試 Google";
      return;
    }
    if (!res.matched || !res.display) {
      out.appendChild(el("p", { class: "gplace-note", text: "Google 搵唔到呢間。" }));
      btn.textContent = "🔎 再試 Google";
      return;
    }
    // Persist ONLY the derived facts (place_id + booleans/bucket) — never the content.
    if (res.facts) savePlaceFacts(r.id, res.facts);

    const d = res.display;
    // Concrete price range first (e.g. 約 HK$50–100), else the $$ bucket.
    const priceText = d.priceRange || (d.priceLevel ? (PRICE_ZH[d.priceLevel] ?? d.priceLevel) : null);
    const rows: (HTMLElement | null)[] = [
      d.phone ? el("div", { class: "gp-row", text: "☎ " + d.phone }) : null,
      priceText ? el("div", { class: "gp-row", text: "💵 " + priceText }) : null,
      d.rating ? el("div", { class: "gp-row", text: `⭐ ${d.rating}${d.userRatingCount ? `（${d.userRatingCount} 評價）` : ""}` }) : null,
      d.openNow != null ? el("div", { class: "gp-row", text: (d.openNow ? "🟢 而家營業中" : "🔴 而家休息") }) : null,
    ];
    if (d.hours?.length) {
      rows.push(el("details", { class: "gp-hours" },
        el("summary", { text: "🕐 營業時間" }),
        el("div", {}, ...d.hours.map((h) => el("div", { class: "gp-hr", text: h })))
      ));
      // Sources differ — nudge users to confirm (OpenRice-style disclaimer).
      rows.push(el("p", { class: "gp-disclaimer", text: "營業時間以餐廳為準，請致電確認。" }));
    }
    if (d.summary) {
      rows.push(el("p", { class: "gp-summary", text: "📝 " + d.summary }));
      rows.push(el("p", { class: "gp-disclose", text: d.summaryDisclosure || "評論摘要由 Google 生成" }));
    } else {
      // Google doesn't generate a reviewSummary for every place — say so honestly.
      rows.push(el("p", { class: "gp-nosummary", text: "Google 暫時未有呢間嘅評論摘要" }));
    }
    out.appendChild(el("div", { class: "gplace-card" }, ...rows.filter(Boolean) as HTMLElement[]));
    // Required attribution + link back to Google Maps.
    out.appendChild(
      el("p", { class: "gplace-attr" },
        "資料來源：Google",
        d.googleMapsUri ? el("a", { class: "gp-link", href: d.googleMapsUri, target: "_blank", rel: "noopener", text: " · 喺 Google 地圖睇" }) : null
      )
    );
    btn.textContent = "🔄 重新查 Google";
  };

  wrap.appendChild(btn);
  wrap.appendChild(out);
  return wrap;
}

function srcLabel(s: Memory["source"]): string {
  return { album: "📸 相簿", receipt: "🧾 單", dish: "🍽️ 碟", manual: "✍️ 手動", onboarding: "🌱 常去" }[s];
}

// ---- catalogue search (基本盤) ---------------------------------------------

const REGIONS: [string, string][] = [["HK", "港島"], ["KLN", "九龍"], ["NT", "新界"]];
const RTYPES: [string, string][] = [["RL", "食肆"], ["RR", "小食"], ["MR", "海鮮舫"]];

function typeLabel(code: string): string {
  return RTYPES.find(([c]) => c === code)?.[1] ?? code;
}

// Restaurant-type icon for the avatar colour block (presentation only).
const TYPE_ICON: Record<string, string> = { RL: "🍽️", RR: "🥡", MR: "🦞" };
let _typeIndex: Map<string, string> | null = null;
function typeIconForId(id: string): string {
  if (state.cat && !_typeIndex) _typeIndex = new Map(state.cat.restaurants.map((r) => [r.id, r.type]));
  return TYPE_ICON[_typeIndex?.get(id) ?? ""] ?? "🍜";
}
// A 56×56 avatar: real photo if the memory has one, else a brand icon block —
// both states look intentional (no empty hole).
function memAvatar(icon: string, photoId?: string): HTMLElement {
  const av = el("div", { class: "mem-avatar" }, el("span", { class: "mem-avatar-icon", text: icon }));
  if (photoId) {
    getPhotoUrl(photoId).then((url) => {
      if (!url) return;
      const img = el("img", { class: "mem-avatar-img", alt: "" }) as HTMLImageElement;
      img.src = url;
      img.addEventListener("load", () => URL.revokeObjectURL(url), { once: true });
      av.appendChild(img); // covers the icon once decrypted
    });
  }
  return av;
}

// ---- per-dish rating (zero-AI, low-friction) -------------------------------
const RATING_BTNS: [Rating, string][] = [
  ["good", "👍 好食"],
  ["ok", "😐 一般"],
  ["bad", "👎 唔好食"],
];
const RATING_EMOJI: Record<Rating, string> = { good: "👍", ok: "😐", bad: "👎" };
// Symmetric, neutral, HK 用語. 👍 → positive; 👎 → negative; 😐 → no chips.
const REASON_POS = ["份量足", "抵食", "新鮮", "夠味", "環境好", "上菜快", "會再嚟"];
const REASON_NEG = ["太咸", "太貴", "份量少", "唔新鮮", "等太耐", "油膩", "唔會再嚟"];
function reasonsFor(rating: Rating | null): string[] {
  return rating === "good" ? REASON_POS : rating === "bad" ? REASON_NEG : [];
}

function catalogueSection(): HTMLElement {
  const results = el("div", { class: "cat-results" });
  const countLbl = el("p", { class: "cat-count" });
  const input = el("input", {
    class: "cat-input",
    type: "search",
    placeholder: `搜尋餐廳名或地區（銅鑼灣、旺角…）`,
    value: state.catQuery,
  }) as HTMLInputElement;

  const renderList = () => {
    clear(results);
    const { items, total } = browseRestaurants(
      state.cat!,
      state.catQuery,
      state.catFilter,
      20
    );
    const filtered = !!(state.catQuery || state.catFilter.region || state.catFilter.type);
    countLbl.textContent = filtered
      ? `${total.toLocaleString()} 間${total > items.length ? `（顯示頭 ${items.length}）` : ""}`
      : `全港 ${(state.cat?.count ?? 0).toLocaleString()} 間 — 搜尋或篩選`;
    if (!filtered) return;
    for (const r of items) {
      results.appendChild(
        el("button", { class: "cat-item", onclick: () => openRestaurant(r.id) },
          el("span", { class: "cat-name", text: r.name.tc }),
          el("span", { class: "cat-area", text: `${typeLabel(r.type)} · ${districtZh(r.area)} · ${regionName(r.region)}` }),
          r.addr ? el("span", { class: "cat-addr", text: r.addr }) : null
        )
      );
    }
  };

  let deb: ReturnType<typeof setTimeout> | null = null;
  input.addEventListener("input", () => {
    if (deb) clearTimeout(deb);
    deb = setTimeout(() => { state.catQuery = input.value; renderList(); }, 130);
  });

  const chip = (label: string, active: boolean, onclick: () => void) =>
    el("button", { class: "cat-chip" + (active ? " on" : ""), text: label, onclick });

  const filterRow = el("div", { class: "cat-filters" },
    ...REGIONS.map(([code, name]) =>
      chip(name, state.catFilter.region === code, () => {
        state.catFilter.region = state.catFilter.region === code ? undefined : code;
        renderList();
        filterRow.replaceWith(buildFilterRow());
      })
    ),
    el("span", { class: "cat-sep" }),
    ...RTYPES.map(([code, name]) =>
      chip(name, state.catFilter.type === code, () => {
        state.catFilter.type = state.catFilter.type === code ? undefined : code;
        renderList();
        filterRow.replaceWith(buildFilterRow());
      })
    )
  );
  function buildFilterRow(): HTMLElement {
    // Rebuild to reflect toggled active states.
    const fr = el("div", { class: "cat-filters" },
      ...REGIONS.map(([code, name]) =>
        chip(name, state.catFilter.region === code, () => {
          state.catFilter.region = state.catFilter.region === code ? undefined : code;
          renderList(); fr.replaceWith(buildFilterRow());
        })),
      el("span", { class: "cat-sep" }),
      ...RTYPES.map(([code, name]) =>
        chip(name, state.catFilter.type === code, () => {
          state.catFilter.type = state.catFilter.type === code ? undefined : code;
          renderList(); fr.replaceWith(buildFilterRow());
        }))
    );
    return fr;
  }

  const section = el("section", { class: "cat-section" },
    el("h3", { class: "sec-title", text: "全港餐廳目錄" }),
    input,
    filterRow,
    countLbl,
    results
  );
  renderList();
  return section;
}

function regionName(code: string): string {
  return { HK: "港島", KLN: "九龍", NT: "新界" }[code] ?? code;
}

// ---- settings (privacy: delete all) ----------------------------------------

// A2: edit taste + active areas directly (not only「全清」or full re-onboarding).
function openPrefsEditor(): void {
  const taste = new Set(getTasteSeed());
  const areas = new Set(getHomeAreas());
  const overlay = el("div", { class: "modal-overlay" });
  const close = () => overlay.remove();
  overlay.addEventListener("click", (e) => { if (e.target === overlay) close(); });

  const chip = (label: string, on: boolean, onclick: () => void) =>
    el("button", { class: "ob2-chip" + (on ? " on" : ""), text: label, onclick });

  const tasteWrap = el("div", { class: "ob2-chips" });
  const drawTaste = () => {
    clear(tasteWrap);
    for (const [label, tag] of TASTE_CHIPS)
      tasteWrap.appendChild(chip(label, taste.has(tag), () => { taste.has(tag) ? taste.delete(tag) : taste.add(tag); drawTaste(); }));
  };
  const areaWrap = el("div", {});
  const drawAreas = () => {
    clear(areaWrap);
    for (const [region, list] of AREA_GROUPS) {
      areaWrap.appendChild(el("p", { class: "ob2-group", text: region }));
      const g = el("div", { class: "ob2-chips" });
      for (const a of list)
        g.appendChild(chip(a, areas.has(a), () => { if (areas.has(a)) areas.delete(a); else if (areas.size < 8) areas.add(a); drawAreas(); }));
      areaWrap.appendChild(g);
    }
  };
  drawTaste(); drawAreas();

  overlay.appendChild(
    el("div", { class: "modal-card" },
      el("button", { class: "modal-close", text: "✕", onclick: close }),
      el("h2", { text: "口味 · 活躍區" }),
      el("label", { class: "log-lbl", text: "你鍾意食咩（可多選）" }),
      tasteWrap,
      el("label", { class: "log-lbl", text: "活躍區（最多 8 個，揀少都得）" }),
      areaWrap,
      el("button", { class: "log-save", text: "儲存", onclick: () => {
        setTasteSeed([...taste]);
        setHomeAreas([...areas]);
        close();
        toast("已更新口味 / 活躍區");
        render();
      } })
    )
  );
  document.body.appendChild(overlay);
}

