// Privacy consent (§5.3). Real consent from v1: the user owns their memories,
// can delete them anytime, and they are never sold. In mock mode all data stays
// on-device (localStorage). NOTE for the real-API step: consent copy MUST be
// updated to cover third-party AI processing of photos/memory before any image
// leaves the device.
const KEY = "dm.consent";

export function hasConsent(): boolean {
  try {
    return localStorage.getItem(KEY) === "v1";
  } catch {
    return false;
  }
}

export function grantConsent(): void {
  try {
    localStorage.setItem(KEY, "v1");
  } catch {
    /* ignore */
  }
}

export function revokeConsent(): void {
  try {
    localStorage.removeItem(KEY);
  } catch {
    /* ignore */
  }
}
