// "未去過" suggestion orchestration (client side).
//  ① own 👍 in the district (free, moat)  ② taste-filter FEHD → tight candidates
//  (free)  ③ Google-check + Haiku synth via /suggest (Phase B)  ④ honest source.
// Cache stores DERIVED facts only (place_id + rating bucket) → same-area re-ask is
// free (template, no Google/Haiku). Falls back to Phase A (names, "未查評價") when
// there's no endpoint or the cap is hit.
import type { Catalogue, Memory, Retrieved } from "./types";
import type { RecallResult, SuggestionItem } from "./recall";
import type { Candidate } from "./taste";
import { areaInQuery, resolveArea } from "./catalogue";
import { deriveTasteProfile, filterByTaste, keywordsForTags, cuisineInQuery, diversify } from "./taste";
import { getTasteSeed, getHomeAreas } from "./onboarding";

const RECALL = (import.meta.env.VITE_RECALL_ENDPOINT as string | undefined) || "";
const ENDPOINT = RECALL ? RECALL.replace(/\/recall$/, "/suggest") : "";

const CACHE_KEY = "dm.suggestCache";
const TTL = 7 * 86400 * 1000;

interface CachedCand { restaurantId: string; name: string; area: string; tag: string; ratingBucket: string | null; placeId: string }

function cacheGet(key: string): CachedCand[] | null {
  try {
    const all = JSON.parse(localStorage.getItem(CACHE_KEY) || "{}");
    const e = all[key];
    if (e && Date.now() - e.ts < TTL) return e.cands;
  } catch { /* ignore */ }
  return null;
}
function cacheSet(key: string, cands: CachedCand[]): void {
  try {
    const all = JSON.parse(localStorage.getItem(CACHE_KEY) || "{}");
    all[key] = { ts: Date.now(), cands };
    localStorage.setItem(CACHE_KEY, JSON.stringify(all));
  } catch { /* ignore */ }
}

// ---- suggestion feedback (client-only signal: teach the system) --------------
const FB_KEY = "dm.suggestFeedback";
export interface SuggestFeedback { dismissed: string[]; visited: string[] }
export function getSuggestFeedback(): SuggestFeedback {
  try {
    const v = JSON.parse(localStorage.getItem(FB_KEY) || "{}");
    return { dismissed: v.dismissed || [], visited: v.visited || [] };
  } catch {
    return { dismissed: [], visited: [] };
  }
}
export function addSuggestFeedback(kind: "dismissed" | "visited", restaurantId: string): void {
  try {
    const v = getSuggestFeedback();
    if (!v[kind].includes(restaurantId)) v[kind].push(restaurantId);
    localStorage.setItem(FB_KEY, JSON.stringify(v));
  } catch { /* ignore */ }
}

const cName = (c: Candidate): string => c.r.name.tc || c.r.name.en;

export async function buildSuggestion(
  query: string,
  memories: Memory[],
  cat: Catalogue
): Promise<RecallResult | null> {
  // Area: from the query, else fall back to the user's home area (onboarding).
  // Home areas are colloquial names (銅鑼灣…) → resolve to the FEHD district.
  const home = getHomeAreas();
  const hit = areaInQuery(query) ?? (home.length ? { area: resolveArea(home[0]) ?? home[0], name: home[0] } : null);
  if (!hit) return null;

  const baseProfile = deriveTasteProfile(memories);
  const liked = [...new Set([...getTasteSeed(), ...baseProfile.liked])];
  const fb = getSuggestFeedback();
  // Exclude visited + user-dismissed / marked-been-there (teach the system).
  const excluded = new Set([...memories.map((m) => m.restaurantId), ...fb.dismissed, ...fb.visited]);

  const queryTags = cuisineInQuery(query);
  const useTags = queryTags.length ? queryTags : liked;
  const effProfile = { liked: useTags, disliked: baseProfile.disliked, keywords: keywordsForTags(useTags) };

  // ① own record in this district: 👍 first, else onboarding "常去".
  const ownGood = memories.filter((m) => m.area === hit.area && m.dishes.some((d) => d.rating === "good"));
  const ownSeed = memories.filter((m) => m.area === hit.area && m.source === "onboarding" && !ownGood.includes(m));
  const ownCited: Retrieved[] = [...ownGood, ...ownSeed].slice(0, 3).map((m) => ({ memory: m, score: 1, relevance: 1 }));
  const ownLine = ownGood.length
    ? `你喺「${hit.name}」👍 過：${[
        ...new Set(ownGood.flatMap((m) => m.dishes.filter((d) => d.rating === "good").map((d) => `${m.restaurantName}嘅${d.name}`))),
      ].slice(0, 3).join("、")}。`
    : ownSeed.length
      ? `你話你常去「${hit.name}」嘅：${[...new Set(ownSeed.map((m) => m.restaurantName))].slice(0, 3).join("、")}。`
      : "";

  // ② taste-filter FEHD → a WIDER, diversified pool (more 款, still customized to
  //    area + taste — NOT a 全港榜單). Google still checks only the top 5 (cost same).
  const TOTAL = 9;
  const candidates = diversify(filterByTaste(cat, hit.area, effProfile, excluded, 24)).slice(0, 12);
  if (!ownGood.length && !ownSeed.length && !candidates.length) return null;

  const key = `${hit.area}|${useTags.slice(0, 4).join(",")}`;
  const lead = "以下呢啲可能啱你口味（撳入睇詳情）：";
  const toItem = (c: (typeof candidates)[number], bucket: string | null = null): SuggestionItem =>
    ({ restaurantId: c.r.id, name: cName(c), area: c.r.area, tag: c.tag, ratingBucket: bucket });
  const result = (items: SuggestionItem[], detail?: string): RecallResult | null => {
    if (!items.length && !ownLine) return null;
    return {
      kind: "recommend",
      cited: ownCited,
      text: [ownLine, items.length ? lead : ""].filter(Boolean).join("\n\n"),
      suggestions: items,
      detail,
    };
  };

  // Cache hit → verified from cache + more taste-matched extras (no Google/Haiku spend).
  const cached = cacheGet(key);
  if (cached) {
    const good = cached.filter((c) => (c.ratingBucket === "高" || c.ratingBucket === "中") && !excluded.has(c.restaurantId));
    if (good.length) {
      const verifiedIds = new Set(good.map((c) => c.restaurantId));
      const verified = good.map((c) => ({ restaurantId: c.restaurantId, name: c.name, area: c.area, tag: c.tag, ratingBucket: c.ratingBucket }));
      const extras = candidates.filter((c) => !verifiedIds.has(c.r.id)).map((c) => toItem(c));
      return result([...verified, ...extras].slice(0, TOTAL));
    }
  }

  // ③ Phase B — server Google-checks the top 5 + Haiku synth (prose = detail).
  if (ENDPOINT && candidates.length) {
    try {
      const byName = new Map(candidates.map((c) => [cName(c), c]));
      const payload = {
        query,
        tags: useTags.slice(0, 6),
        candidates: candidates.map((c) => ({ name: cName(c), addr: c.r.addr, area: c.r.area, tag: c.tag })),
      };
      const res = await fetch(ENDPOINT, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify(payload),
        signal: AbortSignal.timeout(22000),
      });
      if (res.ok) {
        const data = await res.json();
        const facts: { name: string; ratingBucket: string | null; placeId?: string }[] = Array.isArray(data.facts) ? data.facts : [];
        if (facts.length) {
          cacheSet(key, facts.filter((f) => f.placeId && byName.has(f.name)).map((f) => {
            const c = byName.get(f.name)!;
            return { restaurantId: c.r.id, name: f.name, area: c.r.area, tag: c.tag, ratingBucket: f.ratingBucket, placeId: f.placeId! };
          }));
        }
        // Google-verified good picks FIRST, then more taste-matched extras (未查評價).
        const verifiedIds = new Set<string>();
        const verified: SuggestionItem[] = [];
        for (const f of facts) {
          if ((f.ratingBucket === "高" || f.ratingBucket === "中") && byName.has(f.name)) {
            const c = byName.get(f.name)!;
            verifiedIds.add(c.r.id);
            verified.push(toItem(c, f.ratingBucket));
          }
        }
        const bad = new Set(facts.filter((f) => f.ratingBucket && f.ratingBucket !== "高" && f.ratingBucket !== "中").map((f) => f.name));
        const extras = candidates.filter((c) => !verifiedIds.has(c.r.id) && !bad.has(cName(c))).map((c) => toItem(c));
        const items = [...verified, ...extras].slice(0, TOTAL);
        if (items.length) {
          const detail = typeof data.text === "string" && data.text.trim() ? data.text.trim() : undefined;
          return result(items, detail);
        }
      }
    } catch { /* fall through to Phase A */ }
  }

  // ④ Phase A fallback — taste-matched names (「未查評價」), still clickable cards.
  return result(candidates.map((c) => toItem(c)).slice(0, TOTAL));
}
